import { useEffect, useState } from "react";
import { Search } from "../components/Search.jsx";
import { Songs } from "../components/Songs.jsx";
import { Player } from "../components/Player.jsx";
import { SkeletonCard } from "../components/SkeletonCard.jsx";
import { useSongs } from "../hooks/useSongs.js";
import { useFavorites } from "../hooks/useFavorites.js";

export const SearchPage = () => {
  const { songs, loading, error, search, loadMore, hasMore } = useSongs();
  const { toggle, isFav } = useFavorites();
  const [flag, setFlag] = useState(false);
  const [song, setPlayerSong] = useState(null);

  useEffect(() => {
    search("Latest Songs");
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const togglePlayer = (flagVal, songArg) => {
    setPlayerSong(songArg);
    setFlag(flagVal);
  };

  return (
    <div className="container">
      <h1 className="title">Music Store</h1>

      {flag ? (
        <Player fn={togglePlayer} song={song} />
      ) : (
        <>
          <Search fn={search} />

          {loading && (
            <div className="SongListDisplay">
              {Array.from({ length: 8 }).map((_, i) => (
                <SkeletonCard key={i} />
              ))}
            </div>
          )}

          {error && <p className="error-msg">{error}</p>}

          {!loading && !error && (
            <Songs
              fn={togglePlayer}
              allsongs={songs}
              isFav={isFav}
              onFav={toggle}
            />
          )}

          {hasMore && !loading && (
            <div style={{ textAlign: "center", margin: "20px 0" }}>
              <button className="load-more-btn" onClick={loadMore}>
                Load More Songs
              </button>
            </div>
          )}
        </>
      )}
    </div>
  );
};
